18	data class EnrollmentListUiState(
19	    val pendingRequests: List<EnrollmentRequest> = emptyList(),
20	    val myRequests: List<EnrollmentRequest> = emptyList(),
21	    val myEnrollments: List<EnrollmentRecord> = emptyList(),
22	    val pendingTasks: List<EnrollmentApprovalTask> = emptyList(),
23	    val isLoading: Boolean = true,
24	    val errorMessage: String? = null,
25	    val actionMessage: String? = null
26	)
27	
28	@HiltViewModel
29	class EnrollmentListViewModel @Inject constructor(
30	    private val manageEnrollmentUseCase: ManageEnrollmentUseCase
31	) : ViewModel() {
32	
33	    private val _uiState = MutableStateFlow(EnrollmentListUiState())
34	    val uiState: StateFlow<EnrollmentListUiState> = _uiState.asStateFlow()
35	
36	    init {
37	        loadPendingRequestsFlow()
38	        loadMyRequests()
39	        loadMyEnrollments()
40	        loadPendingApprovalTasks()
41	    }
42	
43	    private fun loadPendingRequestsFlow() {
44	        viewModelScope.launch {
45	            manageEnrollmentUseCase.getPendingRequests().collect { requests ->
46	                _uiState.update { it.copy(pendingRequests = requests) }
47	            }
48	        }
49	    }
50	
51	    private fun loadMyRequests() {
52	        viewModelScope.launch {
53	            val requests = manageEnrollmentUseCase.getMyRequests()
54	            _uiState.update { it.copy(myRequests = requests, isLoading = false) }
55	        }
56	    }
57	
58	    private fun loadMyEnrollments() {
59	        viewModelScope.launch {
60	            val enrollments = manageEnrollmentUseCase.getMyEnrollments()
61	            _uiState.update { it.copy(myEnrollments = enrollments) }
62	        }
63	    }
64	
65	    private fun loadPendingApprovalTasks() {
66	        viewModelScope.launch {
67	            val tasks = manageEnrollmentUseCase.getPendingTasksForCurrentUser()
68	            _uiState.update { it.copy(pendingTasks = tasks) }
69	        }
70	    }
71	
72	    fun cancelRequest(requestId: String) {
73	        viewModelScope.launch {
74	            _uiState.update { it.copy(isLoading = true, errorMessage = null) }
75	            when (val result = manageEnrollmentUseCase.cancelRequest(requestId)) {
76	                is AppResult.Success -> {
77	                    _uiState.update {
78	                        it.copy(
79	                            isLoading = false,
80	                            actionMessage = "Request cancelled successfully"
81	                        )
82	                    }
83	                    loadMyRequests()
84	                }
85	                is AppResult.ValidationError -> {
86	                    _uiState.update {
87	                        it.copy(
88	                            isLoading = false,
89	                            errorMessage = result.globalErrors.firstOrNull()
90	                                ?: result.fieldErrors.values.firstOrNull()
91	                                ?: "Cannot cancel request"
92	                        )
93	                    }
94	                }
95	                is AppResult.PermissionError -> {
96	                    _uiState.update {
97	                        it.copy(isLoading = false, errorMessage = "Permission denied")
98	                    }
99	                }
100	                is AppResult.NotFoundError -> {
101	                    _uiState.update {
102	                        it.copy(isLoading = false, errorMessage = "Request not found")
103	                    }
104	                }
105	                is AppResult.ConflictError -> {
106	                    _uiState.update {
107	                        it.copy(isLoading = false, errorMessage = result.message)
108	                    }
109	                }
110	                is AppResult.SystemError -> {
111	                    _uiState.update {
112	                        it.copy(isLoading = false, errorMessage = result.message)
113	                    }
114	                }
115	            }
116	        }
117	    }
118	
119	    fun withdrawEnrollment(recordId: String, reason: String) {
120	        viewModelScope.launch {
121	            _uiState.update { it.copy(isLoading = true, errorMessage = null) }
122	            when (val result = manageEnrollmentUseCase.withdrawEnrollment(recordId, reason)) {
123	                is AppResult.Success -> {
124	                    _uiState.update {
125	                        it.copy(
126	                            isLoading = false,
127	                            actionMessage = "Enrollment withdrawn successfully"
128	                        )
129	                    }
130	                    loadMyEnrollments()
131	                }
132	                is AppResult.ValidationError -> {
133	                    _uiState.update {
134	                        it.copy(
135	                            isLoading = false,
136	                            errorMessage = result.globalErrors.firstOrNull()
137	                                ?: result.fieldErrors.values.firstOrNull()
138	                                ?: "Cannot withdraw enrollment"
139	                        )
140	                    }
141	                }
142	                is AppResult.PermissionError -> {
143	                    _uiState.update {
144	                        it.copy(isLoading = false, errorMessage = "Permission denied")
145	                    }
146	                }
147	                is AppResult.NotFoundError -> {
148	                    _uiState.update {
149	                        it.copy(isLoading = false, errorMessage = "Enrollment not found")
150	                    }
151	                }
152	                is AppResult.ConflictError -> {
153	                    _uiState.update {
154	                        it.copy(isLoading = false, errorMessage = result.message)
155	                    }
156	                }
157	                is AppResult.SystemError -> {
158	                    _uiState.update {
159	                        it.copy(isLoading = false, errorMessage = result.message)
160	                    }
161	                }
162	            }
163	        }
164	    }
165	
166	    fun clearError() {
167	        _uiState.update { it.copy(errorMessage = null) }
168	    }
169	
170	    fun clearActionMessage() {
171	        _uiState.update { it.copy(actionMessage = null) }
172	    }
173	}
