8	import javax.inject.Inject
9	
10	class CheckPermissionUseCase @Inject constructor(
11	    private val roleRepository: RoleRepository,
12	    private val sessionManager: SessionManager
13	) {
14	    suspend fun hasPermission(permission: Permission): Boolean {
15	        val userId = sessionManager.getCurrentUserId() ?: return false
16	        return roleRepository.userHasPermission(userId, permission)
17	    }
18	
19	    suspend fun hasAnyPermission(vararg permissions: Permission): Boolean {
20	        val userId = sessionManager.getCurrentUserId() ?: return false
21	        return permissions.any { roleRepository.userHasPermission(userId, it) }
22	    }
23	
24	    suspend fun hasAllPermissions(vararg permissions: Permission): Boolean {
25	        val userId = sessionManager.getCurrentUserId() ?: return false
26	        return permissions.all { roleRepository.userHasPermission(userId, it) }
27	    }
28	
29	    suspend fun getCurrentUserRoles(): List<RoleType> {
30	        val userId = sessionManager.getCurrentUserId() ?: return emptyList()
31	        return roleRepository.getRoleTypesForUser(userId)
32	    }
33	
34	    suspend fun getCurrentUserPermissions(): Set<Permission> {
35	        val userId = sessionManager.getCurrentUserId() ?: return emptySet()
36	        return roleRepository.getPermissionsForUser(userId)
37	    }
38	
39	    suspend fun <T> requirePermission(
40	        permission: Permission,
41	        block: suspend () -> AppResult<T>
42	    ): AppResult<T> {
43	        if (!hasPermission(permission)) {
44	            return AppResult.PermissionError("Requires ${permission.capability}")
45	        }
46	        return block()
47	    }
48	}
