import com.google.common.truth.Truth.assertThat
import org.junit.Test

/**
 * Tests for the robust CSV/JSON parser in ImportViewModel.
 * Uses the same parsing logic extracted into testable functions.
 */
class ImportParserRobustnessTest {

    // ── CSV parsing helpers (mirror ImportViewModel logic) ──

    private fun parseCsvLine(line: String): List<String> {
        val fields = mutableListOf<String>()
        val current = StringBuilder()
        var inQuotes = false
        var i = 0
        while (i < line.length) {
            val ch = line[i]
            when {
                inQuotes -> {
                    if (ch == '"') {
                        if (i + 1 < line.length && line[i + 1] == '"') {
                            current.append('"')
                            i += 2
                            continue
                        } else {
                            inQuotes = false
                        }
                    } else {
                        current.append(ch)
                    }
                }
                ch == '"' -> inQuotes = true
                ch == ',' -> { fields.add(current.toString()); current.clear() }
                else -> current.append(ch)
            }
            i++
        }
        fields.add(current.toString())
        return fields
    }

    private fun parseCsv(csv: String): List<Map<String, String>>? {
        val lines = csv.lines().filter { it.isNotBlank() }
        if (lines.size < 2) return null
        val headers = parseCsvLine(lines.first()).map { it.trim() }
        val rows = mutableListOf<Map<String, String>>()
        val seenIds = mutableSetOf<String>()
        for (line in lines.drop(1)) {
            val values = parseCsvLine(line)
            val map = mutableMapOf<String, String>()
            headers.forEachIndexed { index, header ->
                if (index < values.size) map[header] = values[index].trim()
            }
            if (map.isEmpty()) continue
            val externalId = map["external_id"]
            if (externalId != null && externalId.isNotBlank()) {
                if (seenIds.contains(externalId)) continue
                seenIds.add(externalId)
            }
            val dateStr = map["transaction_date"]
            if (dateStr != null && dateStr.isNotBlank()) {
                if (!isValidDate(dateStr)) continue
            }
            rows.add(map)
        }
        return if (rows.isEmpty()) null else rows
    }

    private fun isValidDate(dateStr: String): Boolean {
        return try { java.time.Instant.parse(dateStr); true } catch (_: Exception) {
            try { java.time.LocalDate.parse(dateStr); true } catch (_: Exception) {
                try { java.time.LocalDateTime.parse(dateStr); true } catch (_: Exception) { false }
            }
        }
    }

    // ── Tests ──

    @Test
    fun `quoted commas parse correctly`() {
        val csv = """
external_id,amount,payment_reference,tender_type,transaction_date,status
ext-1,"1,000.50",pay-1,CASH,2024-01-15T10:00:00Z,CLEARED
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!!).hasSize(1)
        assertThat(rows[0]["amount"]).isEqualTo("1,000.50")
        assertThat(rows[0]["external_id"]).isEqualTo("ext-1")
    }

    @Test
    fun `escaped quotes in fields parse correctly`() {
        val csv = """
external_id,amount,payment_reference,tender_type,transaction_date,status
ext-1,100.00,"pay ""special"" ref",CASH,2024-01-15T10:00:00Z,CLEARED
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!!).hasSize(1)
        assertThat(rows[0]["payment_reference"]).isEqualTo("pay \"special\" ref")
    }

    @Test
    fun `malformed rows with too few columns still parse available fields`() {
        val csv = """
external_id,amount,payment_reference,tender_type,transaction_date,status
ext-1,100.00
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!!).hasSize(1)
        assertThat(rows[0]["external_id"]).isEqualTo("ext-1")
        assertThat(rows[0]["amount"]).isEqualTo("100.00")
        assertThat(rows[0].containsKey("payment_reference")).isFalse()
    }

    @Test
    fun `invalid dates are rejected`() {
        val csv = """
external_id,amount,payment_reference,tender_type,transaction_date,status
ext-1,100.00,pay-1,CASH,not-a-date,CLEARED
ext-2,200.00,pay-2,CASH,2024-01-15T10:00:00Z,CLEARED
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!!).hasSize(1)
        assertThat(rows[0]["external_id"]).isEqualTo("ext-2")
    }

    @Test
    fun `duplicate external_ids are de-duplicated`() {
        val csv = """
external_id,amount,payment_reference,tender_type,transaction_date,status
ext-1,100.00,pay-1,CASH,2024-01-15T10:00:00Z,CLEARED
ext-1,200.00,pay-2,CASH,2024-01-16T10:00:00Z,CLEARED
ext-2,300.00,pay-3,CASH,2024-01-17T10:00:00Z,CLEARED
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!!).hasSize(2)
        assertThat(rows[0]["external_id"]).isEqualTo("ext-1")
        assertThat(rows[0]["amount"]).isEqualTo("100.00") // First wins
        assertThat(rows[1]["external_id"]).isEqualTo("ext-2")
    }

    @Test
    fun `empty CSV returns null`() {
        assertThat(parseCsv("")).isNull()
        assertThat(parseCsv("just_a_header")).isNull()
    }

    @Test
    fun `whitespace is trimmed from values`() {
        val csv = """
external_id,amount,payment_reference
  ext-1  , 100.00 ,  pay-1
        """.trimIndent()

        val rows = parseCsv(csv)
        assertThat(rows).isNotNull()
        assertThat(rows!![0]["external_id"]).isEqualTo("ext-1")
        assertThat(rows[0]["amount"]).isEqualTo("100.00")
        assertThat(rows[0]["payment_reference"]).isEqualTo("pay-1")
    }

    @Test
    fun `ISO date formats are accepted`() {
        assertThat(isValidDate("2024-01-15T10:00:00Z")).isTrue()
        assertThat(isValidDate("2024-01-15")).isTrue()
        assertThat(isValidDate("2024-01-15T10:00:00")).isTrue()
        assertThat(isValidDate("not-a-date")).isFalse()
        assertThat(isValidDate("13/25/2024")).isFalse()
    }
}
"}

