    @Test
    fun `max cache size is 20MB`() {
        assertThat(ImageMemoryManager.MAX_CACHE_SIZE_BYTES).isEqualTo(20 * 1024 * 1024)
    }

    @Test
    fun `default max dimensions are 1024`() {
        assertThat(ImageMemoryManager.DEFAULT_MAX_WIDTH).isEqualTo(1024)
        assertThat(ImageMemoryManager.DEFAULT_MAX_HEIGHT).isEqualTo(1024)
    }

    @Test
    fun `cache returns null for missing key`() {
        val manager = ImageMemoryManager()
        assertThat(manager.getCachedBitmap("nonexistent")).isNull()
    }

    @Test
    fun `initial cache size is zero`() {
        val manager = ImageMemoryManager()
        assertThat(manager.currentCacheSizeBytes()).isEqualTo(0)
    }

    @Test
    fun `max cache size matches constant`() {
        val manager = ImageMemoryManager()
        assertThat(manager.maxCacheSizeBytes()).isEqualTo(ImageMemoryManager.MAX_CACHE_SIZE_BYTES)
    }
}
"}

