class ManagePolicyUseCaseReadAuthTest {
    private lateinit var policyRepository: PolicyRepository
    private lateinit var auditRepository: AuditRepository
    private lateinit var checkPermission: CheckPermissionUseCase
    private lateinit var sessionManager: SessionManager
    private lateinit var useCase: ManagePolicyUseCase

    private val testPolicy = Policy(
        id = "pol-1", type = PolicyType.COMMERCE, key = "min_order",
        value = "25.00", description = "Minimum order total", version = 1,
        isActive = true, effectiveFrom = Instant.now(), effectiveUntil = null,
        createdBy = "admin-1", createdAt = Instant.now(), updatedAt = Instant.now()
    )

    @Before
    fun setUp() {
        policyRepository = mockk(relaxed = true)
        auditRepository = mockk(relaxed = true)
        checkPermission = mockk()
        sessionManager = mockk()
        every { sessionManager.getCurrentUserId() } returns "admin-1"
        every { sessionManager.getCurrentSessionId() } returns "session-1"
        useCase = ManagePolicyUseCase(policyRepository, auditRepository, checkPermission, sessionManager)
    }

    @Test
    fun `getAllActivePolicies denied without POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns false
        val result = useCase.getAllActivePolicies()
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `getAllActivePolicies succeeds with POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns true
        coEvery { policyRepository.getAllActivePolicies() } returns flowOf(emptyList())
        val result = useCase.getAllActivePolicies()
        assertThat(result).isInstanceOf(AppResult.Success::class.java)
    }

    @Test
    fun `getPoliciesByType denied without POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns false
        val result = useCase.getPoliciesByType(PolicyType.COMMERCE)
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `getPoliciesByType succeeds with POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns true
        coEvery { policyRepository.getActivePoliciesByType(PolicyType.COMMERCE) } returns emptyList()
        val result = useCase.getPoliciesByType(PolicyType.COMMERCE)
        assertThat(result).isInstanceOf(AppResult.Success::class.java)
    }

    @Test
    fun `getPolicyValue denied without POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns false
        val result = useCase.getPolicyValue(PolicyType.COMMERCE, "min_order", "25.00")
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `getPolicyValue succeeds with POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns true
        coEvery { policyRepository.getPolicyValue(PolicyType.COMMERCE, "min_order", "25.00") } returns "30.00"
        val result = useCase.getPolicyValue(PolicyType.COMMERCE, "min_order", "25.00")
        assertThat(result).isInstanceOf(AppResult.Success::class.java)
        assertThat((result as AppResult.Success).data).isEqualTo("30.00")
    }

    @Test
    fun `getPolicyById denied without POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns false
        val result = useCase.getPolicyById("pol-1")
        assertThat(result).isInstanceOf(AppResult.PermissionError::class.java)
    }

    @Test
    fun `getPolicyById succeeds with POLICY_MANAGE permission`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns true
        coEvery { policyRepository.getPolicyById("pol-1") } returns testPolicy
        val result = useCase.getPolicyById("pol-1")
        assertThat(result).isInstanceOf(AppResult.Success::class.java)
        assertThat((result as AppResult.Success).data.id).isEqualTo("pol-1")
    }

    @Test
    fun `getPolicyById returns NotFound for missing policy`() = runTest {
        coEvery { checkPermission.hasPermission(Permission.POLICY_MANAGE) } returns true
        coEvery { policyRepository.getPolicyById("missing") } returns null
        val result = useCase.getPolicyById("missing")
        assertThat(result).isInstanceOf(AppResult.NotFoundError::class.java)
    }
}
"}

