42	
43	    init {
44	        loadDashboardData()
45	    }
46	
47	    private fun loadDashboardData() {
48	        viewModelScope.launch {
49	            _uiState.update { it.copy(isLoading = true) }
50	
51	            val userId = sessionManager.getCurrentUserId()
52	            if (userId == null) {
53	                _uiState.update { it.copy(isLoading = false, isLoggedOut = true) }
54	                return@launch
55	            }
56	
57	            val user = userRepository.getUserById(userId)
58	            val displayName = user?.displayName ?: ""
59	
60	            val roles = checkPermissionUseCase.getCurrentUserRoles()
61	            val hasAuditPerm = checkPermissionUseCase.hasPermission(Permission.AUDIT_VIEW)
62	
63	            _uiState.update {
64	                it.copy(
65	                    displayName = displayName,
66	                    roles = roles,
67	                    hasAuditPermission = hasAuditPerm
68	                )
69	            }
70	
71	            // Only collect audit events if the user has permission
72	            if (hasAuditPerm) {
73	                collectRecentAuditEvents()
74	            } else {
75	                _uiState.update { it.copy(isLoading = false) }
76	            }
77	        }
78	    }
79	
