81	        viewModelScope.launch {
82	            when (val result = viewAuditLogUseCase.getRecentEvents(limit = 10)) {
83	                is AppResult.Success -> {
84	                    result.data.collect { events ->
85	                        _uiState.update {
86	                            it.copy(
87	                                recentAuditEvents = events,
88	                                isLoading = false
89	                            )
90	                        }
91	                    }
92	                }
93	                is AppResult.PermissionError -> {
94	                    _uiState.update {
95	                        it.copy(
96	                            recentAuditEvents = emptyList(),
97	                            hasAuditPermission = false,
98	                            isLoading = false
99	                        )
100	                    }
101	                }
102	                else -> {
103	                    _uiState.update { it.copy(isLoading = false) }
104	                }
105	            }
106	        }
107	    }
