    fun provideDatabase(@ApplicationContext context: Context): LearnMartRoomDatabase {
        // Attempt SQLCipher-encrypted database; fall back to unencrypted if it fails.
        // This ensures the app remains usable even on environments where SQLCipher
        // native libs or Android Keystore behave unexpectedly.
        val factory: SupportFactory? = try {
            val passphrase = SQLiteDatabase.getBytes(getOrCreateDatabaseKey(context).toCharArray())
            SupportFactory(passphrase)
        } catch (e: Exception) {
            Log.e(TAG, "SQLCipher init failed — using unencrypted DB: ${e.message}", e)
            null
        }

        val dbName = if (factory != null) "learnmart_encrypted.db" else "learnmart_unencrypted.db"

        val builder = Room.databaseBuilder(
            context,
            LearnMartRoomDatabase::class.java,
            dbName
        )

        if (factory != null) {
            builder.openHelperFactory(factory)
        }

        return builder
            .addMigrations(MIGRATION_5_6)
            .fallbackToDestructiveMigration()
            .addCallback(object : RoomDatabase.Callback() {
                override fun onDestructiveMigration(db: SupportSQLiteDatabase) {
                    Log.w(
                        TAG,
